const d = $json;
const required = ['leadSku','leadPhone','language'];
const missing = required.filter(k => !d[k]);
if (missing.length) throw new Error('WF-03: datos faltantes: ' + missing.join(', '));
return [{ json: {
  leadSku:    d.leadSku,
  leadPhone:  d.leadPhone,
  remoteJid:  d.remoteJid || d.leadPhone + '@s.whatsapp.net',
  language:   d.language || 'en',
  leadName:   d.leadName || '',
  mesElegido: d.mesElegido || 'the requested month',
  estadoAnterior: d.leadEstado || 'cotizacion_enviada'
}}];

const ctx = $('Validar datos de entrada').item.json;
const isEs = ctx.language === 'es';
const mes = ctx.mesElegido;
const msg = isEs
  ? `¡Hola ${ctx.leadName || 'ahí'}! Revisé la agenda y ${mes} está con muy poca disponibilidad 😔 Sin embargo, tenemos excelentes fechas disponibles el mes siguiente. ¿Te interesaría una de esas opciones? 📅`
  : `Hi ${ctx.leadName || 'there'}! I checked our schedule and ${mes} is quite full 😔 However, we have great availability the following month. Would one of those dates work for you? 📅`;
return [{ json: { ...ctx, mensajeParaLead: msg, nuevoEstado: 'cotizacion_enviada' } }];

const ctx = $('Validar datos de entrada').item.json;
const isEs = ctx.language === 'es';
const mes = ctx.mesElegido;
const deposito = $env['DEPOSIT_AMOUNT_USD'] || '500';
const diasAviso = $env['RESERVATION_POLICY_DAYS'] || '5';
const msg = isEs
  ? `¡Excelentes noticias ${ctx.leadName || ''}! 🎉 ${mes} está disponible.

Para confirmar y reservar tu lugar, necesitamos un depósito de $${deposito} USD.

Política de reagendamiento: puedes cambiar tu fecha con un mínimo de ${diasAviso} días de anticipación sin ningún costo. 😊

¿Prefieres pagar por PayPal o por transferencia bancaria/Zelle?`
  : `Great news ${ctx.leadName || ''}! 🎉 ${mes} is available!

To confirm and secure your spot, we need a $${deposito} USD deposit.

Rescheduling policy: you can change your date with at least ${diasAviso} days notice at no cost. 😊

Would you prefer to pay via PayPal or bank transfer/Zelle?`;
return [{ json: { ...ctx, mensajeParaLead: msg, nuevoEstado: 'pago_pendiente' } }];
